-- 현재 AWR 설정 확인
SELECT DBID, SNAP_INTERVAL, RETENTION, TOPNSQL
FROM DBA_HIST_WR_CONTROL;

-- AWR 스냅샷 주기를 30분, 보존기간을 30일로 변경
BEGIN
  DBMS_WORKLOAD_REPOSITORY.MODIFY_SNAPSHOT_SETTINGS(
    retention => 30 * 24 * 60,  -- 30일 (분 단위)
    interval  => 30             -- 30분
  );
END;
/

-- 변경 후 설정 확인
SELECT DBID, SNAP_INTERVAL, RETENTION, TOPNSQL
FROM DBA_HIST_WR_CONTROL;
